import { updateRef } from '../util/composeRefs';
import { useResizeObserver } from '@universe-design/react-utilities';
import type { UseResizeObserverCallback } from '@universe-design/react-utilities';
import { useIsomorphicLayoutEffect as useLayoutEffect } from './useIsomorphicLayoutEffect';

export function useRcVirtualListResizeObserver({
  getContainer,
  onHolderResize,
  onHolderChildResize,
}: {
  getContainer: () => HTMLElement | undefined | null;
  onHolderResize: UseResizeObserverCallback;
  onHolderChildResize: UseResizeObserverCallback;
}) {
  const vListHolderRef = useResizeObserver<HTMLDivElement>(onHolderResize);

  const vListHolderChildRef = useResizeObserver<HTMLDivElement>(onHolderChildResize);

  useLayoutEffect(() => {
    // 由于 virtual-list 由我们渲染，并且内部没有卸载逻辑，所以 holder 和 holder child 在 virtual-list 内部 rerender 时是引用是不变的，可以用这个方式来模拟获取 ref
    const holderCSSSelector = '.rc-virtual-list-holder';
    const container = getContainer();
    const vListHolder = container?.querySelector<HTMLDivElement>(holderCSSSelector) ?? undefined;
    updateRef(vListHolderRef, vListHolder);
    updateRef(vListHolderChildRef, container?.querySelector<HTMLDivElement>(`${holderCSSSelector} > div`) ?? undefined);

    return () => {
      updateRef(vListHolderRef, null);
      updateRef(vListHolderChildRef, null);
    };
  }, [getContainer, vListHolderChildRef, vListHolderRef]);

  return { vListHolderRef, vListHolderChildRef };
}
